{
  "guidedPractice": {
    "title": "Guided Practice: Categorising Safety and Installation Documents",
    "objective": "Categorise industry documents into statutory or non-statutory groups using the 'Law vs. Guidance' rule.",
    "retrievalTextLines": [
      "Statutory regulations are mandatory laws passed by Parliament (the 'Law of the Land').",
      "Non-statutory regulations are guidance documents and codes of practice (the 'Industry Playbook').",
      "To classify a document, ask: Is this a legal requirement I must follow by law, or is it a guide on how to do the job safely?"
    ],
    "questionText": "You are reviewing your site documentation. You have the Health and Safety at Work Act (HASAWA) and the On-Site Guide. Based on their legal status, classify each one as either Statutory or Non-statutory.",
    "answerGuidance": [
      "HASAWA is Statutory",
      "On-Site Guide is Non-statutory"
    ],
    "hint": "Remember: Acts of Parliament are always statutory. Handbooks that simplify technical rules are non-statutory."
  },
  "practice": {
    "title": "Independent Practice: Regulatory Classification",
    "objective": "Independently identify the correct regulatory category for specific electrical industry documents from the provided range.",
    "retrievalTextLines": [
      "The industry relies on a mix of mandatory legislation and technical guidance.",
      "Statutory examples include COSHH and PPE Regulations.",
      "Non-statutory examples include Guidance Notes and Codes of Practice."
    ],
    "questionText": "Classify the following three items as either Statutory or Non-statutory: COSHH, PPE Regulations, and Guidance Notes.",
    "answerGuidance": [
      "COSHH and PPE Regulations are Statutory; Guidance Notes are Non-statutory"
    ],
    "hint": "Think about which ones are legal requirements for safety on site versus which ones provide technical advice."
  }
}

{
  "integrative": {
    "title": "Integrative Close",
    "objective": "Differentiate between the legal standing of the EAWR and BS 7671, explaining the relationship between statutory law and non-statutory guidance.",
    "retrievalTextLines": [
      "Statutory regulations like the EAWR are mandatory laws passed by Parliament.",
      "Non-statutory documents like BS 7671 provide the technical standards and guidance.",
      "Following non-statutory guidance is the recognized way to prove you have met your statutory legal duties."
    ],
    "questionText": "An apprentice on site asks you why they need to bother with BS 7671 if the Electricity at Work Regulations (EAWR) is the actual law. Explain the relationship between these two documents, specifically identifying which one is statutory and how the non-statutory document helps an electrician fulfill their legal obligations.",
    "answerGuidance": [
      "EAWR is the statutory regulation (mandatory law).",
      "BS 7671 is the non-statutory regulation (guidance/technical standard).",
      "Following the guidance in BS 7671 is the primary way to prove that an electrician has complied with the legal duties set out in the EAWR."
    ],
    "hint": "Think about which one is the 'Law of the Land' and which one is the 'Industry Playbook' used to meet that law."
  }
}

